import{_ as s,C as d,o as e,c as i,a4 as t,b as n,w as o,a as l,E as c,a5 as u}from"./chunks/framework.4M7SpZrd.js";const x=JSON.parse('{"title":"Pagamentos — Fluxos e Integracao","description":"","frontmatter":{},"headers":[],"relativePath":"api/payments.md","filePath":"api/payments.md"}'),m={name:"api/payments.md"};function p(h,a,b,A,P,g){const r=d("Mermaid");return e(),i("div",null,[a[1]||(a[1]=t('<h1 id="pagamentos-—-fluxos-e-integracao" tabindex="-1">Pagamentos — Fluxos e Integracao <a class="header-anchor" href="#pagamentos-—-fluxos-e-integracao" aria-label="Permalink to &quot;Pagamentos — Fluxos e Integracao&quot;">​</a></h1><blockquote><p><strong>Endpoints completos:</strong> <a href="http://kubex.test/api/docs#/payments" target="_blank" rel="noreferrer">Swagger UI — Payments</a></p></blockquote><p>Integracao com gateway <strong>Asaas</strong> (PIX, cartao, boleto).</p><hr><h2 id="planos" tabindex="-1">Planos <a class="header-anchor" href="#planos" aria-label="Permalink to &quot;Planos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plano</th><th>Preco</th><th>Visibilidade</th><th>Status</th></tr></thead><tbody><tr><td>Gratuito</td><td>R$ 0</td><td>Publico</td><td>Ativo</td></tr><tr><td>Essencial</td><td>R$ 39/mes</td><td>Publico</td><td>Ativo</td></tr><tr><td>Pro</td><td>R$ 89/mes</td><td>Publico</td><td>Ativo (destacado)</td></tr><tr><td>Fundador</td><td>R$ 39/mes (congelado)</td><td>Legacy (nao publico)</td><td>Ativo para existentes</td></tr><tr><td>Premium</td><td>R$ 199/mes</td><td>Nao publico</td><td>Desativado</td></tr></tbody></table><p>Para detalhes de features por plano, ver <a href="./overview#matriz-de-features-por-plano">Visao Geral — Matriz de Features</a>.</p><hr><h2 id="fluxo-de-assinatura" tabindex="-1">Fluxo de Assinatura <a class="header-anchor" href="#fluxo-de-assinatura" aria-label="Permalink to &quot;Fluxo de Assinatura&quot;">​</a></h2><ol><li><code>POST /payments/subscribe</code> com <code>plan</code> + <code>payment_method</code> (pix, credit_card, boleto)</li><li>Cria customer no Asaas (se nao existir)</li><li>Cria subscription no Asaas</li><li>Retorna URL de pagamento (PIX QR code, link cartao, ou boleto)</li><li>Webhook confirma pagamento → ativa plano</li></ol>',10)),(e(),n(u,null,{default:o(()=>[c(r,{id:"mermaid-139",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20U%20as%20Usuario%0A%20%20%20%20participant%20K%20as%20Kubex%20API%0A%20%20%20%20participant%20A%20as%20Asaas%0A%20%20%20%20U-%3E%3EK%3A%20POST%20%2Fpayments%2Fsubscribe%0A%20%20%20%20K-%3E%3EA%3A%20Criar%20customer%20%2B%20subscription%0A%20%20%20%20A--%3E%3EK%3A%20URL%20de%20pagamento%0A%20%20%20%20K--%3E%3EU%3A%20URL%20(PIX%2Fcartao%2Fboleto)%0A%20%20%20%20U-%3E%3EA%3A%20Efetua%20pagamento%0A%20%20%20%20A-%3E%3EK%3A%20Webhook%20PAYMENT_CONFIRMED%0A%20%20%20%20K-%3E%3EK%3A%20Ativa%20plano%20do%20usuario%0A"})]),fallback:o(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=t('<hr><h2 id="pay-per-search" tabindex="-1">Pay-per-Search <a class="header-anchor" href="#pay-per-search" aria-label="Permalink to &quot;Pay-per-Search&quot;">​</a></h2><p><code>POST /payments/unlock-search</code> — pagamento avulso para desbloquear resultados de uma busca especifica. Destinado a usuarios do plano Gratuito que desejam ver resultados completos sem assinar.</p><hr><h2 id="webhook-post-payments-webhook" tabindex="-1">Webhook (<code>POST /payments/webhook</code>) <a class="header-anchor" href="#webhook-post-payments-webhook" aria-label="Permalink to &quot;Webhook (`POST /payments/webhook`)&quot;">​</a></h2><p>Recebe eventos do Asaas via webhook. Seguranca: verificacao de assinatura do payload, rate limit Nginx <code>60r/m</code>, audit log em todos eventos.</p><table tabindex="0"><thead><tr><th>Evento Asaas</th><th>Acao</th></tr></thead><tbody><tr><td><code>PAYMENT_CONFIRMED</code></td><td>Ativa assinatura ou desbloqueia busca avulsa</td></tr><tr><td><code>PAYMENT_OVERDUE</code></td><td>Marca usuario como inadimplente</td></tr><tr><td><code>PAYMENT_REFUNDED</code></td><td>Processa reembolso</td></tr><tr><td><code>SUBSCRIPTION_CANCELLED</code></td><td>Reverte para plano Gratuito</td></tr></tbody></table><h3 id="tratamento-de-falhas" tabindex="-1">Tratamento de Falhas <a class="header-anchor" href="#tratamento-de-falhas" aria-label="Permalink to &quot;Tratamento de Falhas&quot;">​</a></h3><ul><li><strong>Pagamento nao confirmado em 48h:</strong> assinatura permanece pendente; usuario mantem plano atual</li><li><strong>Webhook falha:</strong> Asaas reenvia automaticamente (retry exponencial)</li><li><strong>Assinatura cancelada:</strong> usuario reverte para plano Gratuito no proximo ciclo de billing</li></ul><hr><h2 id="mock-mode" tabindex="-1">Mock Mode <a class="header-anchor" href="#mock-mode" aria-label="Permalink to &quot;Mock Mode&quot;">​</a></h2><p>Quando <code>ASAAS_API_KEY</code> ausente, o sistema opera em modo mock:</p><ul><li>Retorna IDs ficticios (<code>cus_mock_xxx</code>, <code>sub_mock_xxx</code>)</li><li>Nenhuma chamada externa realizada</li><li>Permite testar fluxo completo em ambiente dev</li></ul><hr><h2 id="seguranca" tabindex="-1">Seguranca <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Seguranca&quot;">​</a></h2><ul><li>Payload do webhook verificado por assinatura</li><li>Rate limit Nginx: 60 req/min no endpoint de webhook</li><li>Audit log em todos os eventos de pagamento</li><li>Dados de cartao nunca trafegam pela API Kubex (processados diretamente pelo Asaas)</li></ul>',16))])}const f=s(m,[["render",p]]);export{x as __pageData,f as default};
